    console.log('║                    ADMIN CREDENTIALS                         ║');
    console.log('╠══════════════════════════════════════════════════════════════╣');
    console.log(`║  Username: ${ADMIN_USERNAME.padEnd(48)}║`);
    console.log(`║  Password: ${defaultPassword.padEnd(48)}║`);
    console.log('║                                                              ║');
    console.log('║  Set ADMIN_PASSWORD env var to use your own password.        ║');
    console.log('╚══════════════════════════════════════════════════════════════╝');
    console.log('');
  }
